('jpms_ec_0035','PATHS教育プログラム','PATHS Curriculum','Promoting Alternative Thinking Strategies','SEL program developed by Mark T. Greenberg teaching emotional understanding, problem-solving, self-control in stages. Visual curriculum and classroom environment design.','Prevention-oriented SEL with proven long-term improvements in academic outcomes for disadvantaged children.','sel','Social-Emotional Learning Research',1994,NULL,'Cognitive-only approaches','PATHS,emotions,problem-solving,self-regulation','PATHS,emotional understanding,problem-solving,self-regulation','["Mark T. Greenberg","Carol A. Kusche"]','[{"title":"Improving young children social and emotional competence: A randomized trial of the preschool PATHS curriculum","year":2007,"doi":"10.1007/s10935-007-0081-0","verified":false,"source_id":"jpms_src_010302"}]',90,'pending_verification','primary',75),

('jpms_ec_0036','RULER実践法','RULER Approach','Recognizing, Understanding, Labeling, Expressing, Regulating','Emotional intelligence education method developed at Yale by Marc Brackett. Five skills: recognition, understanding, labeling, expression, regulation taught in stages.','Model for school implementation of emotional intelligence with proven improvements in classroom quality and academic outcomes.','sel','Social-Emotional Learning Research',2005,NULL,'Emotion avoidance approaches','RULER,emotional intelligence,Yale,Brackett','RULER,emotional intelligence,Yale,Brackett','["Marc A. Brackett","Christina S. Bailey"]','[{"title":"RULER: A Theory-Driven, Systemic Approach to Social, Emotional, and Academic Learning","year":2019,"doi":"10.1080/00461520.2019.1614447","verified":false,"source_id":"jpms_src_010303"}]',92,'pending_verification','primary',76),

('jpms_ec_0037','Second Stepプログラム','Second Step Program','Second Step','SEL program by Committee for Children teaching self-control, empathy, problem-solving in grades K-5. Universal approach for bullying prevention.','Standard SEL program adopted by 25,000+ schools worldwide with proven reductions in violence.','sel','Social-Emotional Learning Research',1987,NULL,'Reactive approaches','Second Step,self-control,empathy','Second Step,self-control,empathy,bullying prevention','["Committee for Children","Abigail Espelage"]','[{"title":"Promoting social-emotional competence: An evaluation of the elementary version of Second Step","year":2016,"doi":"10.1007/s10802-016-0142-1","verified":false,"source_id":"jpms_src_010304"}]',90,'pending_verification','primary',75),

('jpms_ec_0038','MindUPプログラム','MindUP Mindfulness Curriculum','MindUP','Mindfulness program by Goldie Hawn Foundation with 12 weekly lessons promoting attention, emotion control, social thinking based on neuroscience.','Proven model for improving executive function, stress reduction, and academic achievement. Adopted as standard program in Canada, Australia, UK.','sel','Social-Emotional Learning Research',2003,NULL,'Cognitive therapy approaches','MindUP,mindfulness,attention,neuroscience','MindUP,mindfulness,attention,neuroscience','["Katherine E. Schonert-Reichl","Robert J. Roeser"]','[{"title":"Enhancing Cognitive and Social-Emotional Development Through a Simple-to-Administer Mindfulness-Based School Program","year":2016,"doi":"10.1111/cdep.12170","verified":false,"source_id":"jpms_src_010305"}]',88,'pending_verification','primary',75),

('jpms_ec_0039','学校でのマインドフルネス実装メタ分析','Mindfulness-Based Interventions in Schools Meta-Analysis','Mindfulness in schools','Meta-analysis of 24 studies by Zenner et al. of 1,348 students on mindfulness interventions in schools for cognitive performance, stress, and resilience.','First comprehensive meta-analysis of school mindfulness implementation effectiveness, providing scientific foundation for worldwide program adoption.','sel','Social-Emotional Learning Research',2014,NULL,'Mindfulness skepticism','mindfulness,meta-analysis,schools,cognition','mindfulness,meta-analysis,schools,cognitive performance','["Charlotte Zenner","Solveig Herrnleben-Kurz","Harald Walach"]','[{"title":"Mindfulness-based interventions in schools: a systematic review and meta-analysis","year":2014,"doi":"10.3389/fpsyg.2014.00603","verified":false,"source_id":"jpms_src_010306"}]',89,'pending_verification','primary',77),

('jpms_ec_0040','修復的実践','Restorative Practices','Restorative Practices','Approach to resolving conflicts restorative dialogue. Problem-solving circles, restorative conferences, peer mediation. Promotes relationship repair.','Proven more effective than punitive discipline for reducing school violence, absenteeism, racial injustice. Expanding adoption in US, Canada, Australia.','sel','Social-Emotional Learning Research',2010,NULL,'Punitive discipline models','restorative,conflict,dialogue,circles','restorative practices,conflict resolution,dialogue','["Patricia Hernandez-Castilla"]','[{"title":"Restorative practices in reducing school violence: a systematic review","year":2025,"doi":"10.3389/feduc.2025.1520137","verified":false,"source_id":"jpms_src_010307"}]',93,'pending_verification','primary',76),

('jpms_ec_0041','トラウマインフォームド教育','Trauma-Informed Education','Trauma-Informed Practices','School implementation addressing trauma from abuse, violence, poverty. Five principles: safety, trust, choice, collaboration, empowerment (STCCE).','Proven effective for improving academic achievement and behavior in trauma-affected students. Becoming standard in US and Canada.','sel','Social-Emotional Learning Research',2013,NULL,'Uniform classroom management','trauma-informed,safety,support','trauma-informed,safety,psychosocial support','["Nicholas D. Jones","Suhui Lay"]','[{"title":"Effects of trauma-informed approaches in schools: A systematic review","year":2019,"doi":"10.1002/CL2.177","verified":false,"source_id":"jpms_src_010308"}]',90,'pending_verification','primary',76),

('jpms_ec_0042','いじめ予防プログラム','Olweus Bullying Prevention Program','Olweus Program','Whole-school bullying prevention by Dan Olweus. Four-level integration: school environment, classroom discipline, victim support, perpetrator intervention.','Largest evidence study (70,998 students) shows 3% reduction in bullying. Adopted by 50+ countries as international standard for violence prevention.','sel','Social-Emotional Learning Research',1983,NULL,'Individual bullying response','Olweus,bullying,prevention','Olweus,bullying prevention,school environment','["Dan Olweus","Valerie E. Lee"]','[{"title":"Evaluation of the Olweus Bullying Prevention Program: A large scale study","year":2018,"doi":"10.1080/15388220.2017.1314186","verified":false,"source_id":"jpms_src_010309"}]',95,'pending_verification','primary',77),

('jpms_ec_0043','共感スキルトレーニング','Empathy Development in Adolescence','Empathy Skills Training','Educational intervention promoting cognitive and emotional empathy in adolescence. Teaches perspective-taking, emotional attunement, prosocial behavior with cultural adaptation.','Core component of SEL improving relationships, citizenship, mental health. High effectiveness in low-income and crisis contexts.','sel','Social-Emotional Learning Research',2015,NULL,'Perspective-taking unnecessary','empathy,adolescence,prosocial','empathy,adolescent development,prosocial behavior','["Miriam Behforouz","Jacqueline C. Shantz"]','[{"title":"Rethinking empathy development in childhood and adolescence","year":2025,"doi":"10.3389/fpsyg.2025.1575249","verified":false,"source_id":"jpms_src_010310"}]',88,'pending_verification','primary',75),

